import React, { useEffect, useState } from "react";
import { Container, Box, Typography, Divider, Link, Grid, Button } from "@mui/material";

function SecondInterviewAdjustmentScreen({
  profileData,
  casualData,
  firstInterviewData,
  secondInterviewData,
}) {
  const [photoPreviewUrl, setPhotoPreviewUrl] = useState(null);
  const [resumePreviewUrl, setResumePreviewUrl] = useState(null);
  const [careerSheetPreviewUrl, setCareerSheetPreviewUrl] = useState(null);

  useEffect(() => {
    if (profileData.photo) {
      const url = URL.createObjectURL(profileData.photo);
      setPhotoPreviewUrl(url);
      return () => URL.revokeObjectURL(url);
    }
  }, [profileData.photo]);

  useEffect(() => {
    if (profileData.resume) {
      const url = URL.createObjectURL(profileData.resume);
      setResumePreviewUrl(url);
      return () => URL.revokeObjectURL(url);
    }
  }, [profileData.resume]);

  useEffect(() => {
    if (profileData.careerSheet) {
      const url = URL.createObjectURL(profileData.careerSheet);
      setCareerSheetPreviewUrl(url);
      return () => URL.revokeObjectURL(url);
    }
  }, [profileData.careerSheet]);

  // 二次面接データの保存処理
  const handleSaveSecondInterview = async () => {
    // profileData.id には候補者登録時に取得したIDがセットされている前提
    const secondInterviewPayload = {
      candidate_id: profileData.id,
      technical_skills: secondInterviewData.technicalSkills,
      problem_solving: secondInterviewData.problemSolving,
      logical_thinking: secondInterviewData.logicalThinking,
      leadership: secondInterviewData.leadership,
      career_vision: secondInterviewData.careerVision,
    };

    console.log("送信前の二次面接データ:", secondInterviewPayload);
    try {
      const response = await fetch("http://localhost:3001/second_interviews/", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(secondInterviewPayload),
      });
      if (response.ok) {
        const data = await response.json();
        console.log("二次面接データ登録成功", data);
        // 必要に応じて成功時のフィードバックを追加
      } else {
        console.error("二次面接データ登録エラー:", response.statusText);
      }
    } catch (error) {
      console.error("ネットワークエラー:", error);
    }
  };

  return (
    <Container maxWidth="md" sx={{ py: 4 }}>
      <Grid container spacing={4}>
        {/* カジュアル面談結果 */}
        <Grid item xs={12} sm={6} md={3}>
          <Box>
            <Typography variant="h5" gutterBottom>
              カジュアル
            </Typography>
            <Typography variant="body1">
              <strong>判定結果:</strong> {casualData.result || "未入力"}
            </Typography>
            <Typography variant="body1">
              <strong>誠実:</strong> {casualData.honesty || "未入力"}
            </Typography>
            <Typography variant="body1">
              <strong>チーム愛:</strong> {casualData.teamLove || "未入力"}
            </Typography>
            <Typography variant="body1">
              <strong>愛嬌:</strong> {casualData.charm || "未入力"}
            </Typography>
            <Typography variant="body1">
              <strong>謙虚さと責任感:</strong> {casualData.humility || "未入力"}
            </Typography>
            <Typography variant="body1">
              <strong>備考記入欄:</strong> {casualData.notes || "未入力"}
            </Typography>
          </Box>
        </Grid>

        {/* 1次面接結果 */}
        <Grid item xs={12} sm={6} md={3}>
          <Box>
            <Typography variant="h5" gutterBottom>
              1次面接
            </Typography>
            <Typography variant="body1">
              <strong>専門知識・技術力:</strong>{" "}
              {firstInterviewData.technicalSkills || "未入力"}
            </Typography>
            <Typography variant="body1">
              <strong>問題解決能力:</strong>{" "}
              {firstInterviewData.problemSolving || "未入力"}
            </Typography>
            <Typography variant="body1">
              <strong>論理的思考力:</strong>{" "}
              {firstInterviewData.logicalThinking || "未入力"}
            </Typography>
            <Typography variant="body1">
              <strong>リーダーシップ・主体性:</strong>{" "}
              {firstInterviewData.leadership || "未入力"}
            </Typography>
            <Typography variant="body1">
              <strong>キャリアビジョン:</strong>{" "}
              {firstInterviewData.careerVision || "未入力"}
            </Typography>
          </Box>
        </Grid>

        {/* 2次面接結果 */}
        <Grid item xs={12} sm={6} md={3}>
          <Box>
            <Typography variant="h5" gutterBottom>
              2次面接
            </Typography>
            <Typography variant="body1">
              <strong>専門知識・技術力:</strong>{" "}
              {secondInterviewData.technicalSkills || "未入力"}
            </Typography>
            <Typography variant="body1">
              <strong>問題解決能力:</strong>{" "}
              {secondInterviewData.problemSolving || "未入力"}
            </Typography>
            <Typography variant="body1">
              <strong>論理的思考力:</strong>{" "}
              {secondInterviewData.logicalThinking || "未入力"}
            </Typography>
            <Typography variant="body1">
              <strong>リーダーシップ・主体性:</strong>{" "}
              {secondInterviewData.leadership || "未入力"}
            </Typography>
            <Typography variant="body1">
              <strong>キャリアビジョン:</strong>{" "}
              {secondInterviewData.careerVision || "未入力"}
            </Typography>
            <Box sx={{ display: "flex", justifyContent: "flex-end", mt: 2 }}>
              <Button variant="contained" onClick={handleSaveSecondInterview} sx={{ fontSize: "0.8rem" }}>
                保存
              </Button>
            </Box>
          </Box>
        </Grid>
      </Grid>
    </Container>
  );
}

export default SecondInterviewAdjustmentScreen;
